5	function countNeighbors(x: number, y: number, alive: Set<string>): number {
6	  let count = 0;
7	  for (let dx = -1; dx <= 1; dx++) {
8	    for (let dy = -1; dy <= 1; dy++) {
9	      if (dx === 0 && dy === 0) continue;
10	      if (alive.has(toKey(x + dx, y + dy))) count++;
11	    }
12	  }
13	  return count;
14	}
