16	export function nextGeneration(cells: [number, number][]): [number, number][] {
17	  const alive = new Set(cells.map(([x, y]) => toKey(x, y)));
18	
19	  return cells.filter(([x, y]) => {
20	    const neighbors = countNeighbors(x, y, alive);
